import { useState } from "react";
import { supabase } from "../supabaseClient";

export default function CreatePost({ onPostCreated }) {
  const [content, setContent] = useState("");
  const [category, setCategory] = useState("Discussion"); // 🔥 New field
  const [topic, setTopic] = useState("Design"); // 🔥 New field
  const [images, setImages] = useState([]); // 🔥 multiple images
  const [previews, setPreviews] = useState([]); // 🔥 multiple previews
  const [loading, setLoading] = useState(false);

  // 📸 Handle multiple image select
  const handleImageChange = (e) => {
    const files = Array.from(e.target.files);

    if (!files.length) return;

    setImages(files);

    const previewUrls = files.map((file) =>
      URL.createObjectURL(file)
    );
    setPreviews(previewUrls);
  };

  // 🚀 Handle post
  const handlePost = async () => {
    if (!content && images.length === 0) {
      alert("Please add content or image");
      return;
    }

    setLoading(true);

    const { data: userData, error: userError } =
      await supabase.auth.getUser();

    if (userError || !userData.user) {
      alert("User not logged in");
      setLoading(false);
      return;
    }

    const user = userData.user;

    let imageUrls = [];

    // ================= MULTIPLE IMAGE UPLOAD =================
    if (images.length > 0) {
      for (let img of images) {
        const fileName = `${Date.now()}-${img.name}`;

        const { error: uploadError } = await supabase.storage
          .from("post-images")
          .upload(fileName, img);

        if (uploadError) {
          console.log("UPLOAD ERROR:", uploadError.message);
          alert(uploadError.message);
          setLoading(false);
          return;
        }

        const { data } = supabase.storage
          .from("post-images")
          .getPublicUrl(fileName);

        imageUrls.push(data.publicUrl);
      }
    }

    // ================= INSERT POST =================
    const { error: insertError } = await supabase.from("posts").insert([
      {
        user_id: user.id,
        content,
        category, // 🔥 Save Category
        topic,    // 🔥 Save Topic
        image_urls: imageUrls, // 🔥 array
      },
    ]);

    if (insertError) {
      console.log("INSERT ERROR:", insertError.message);
      alert("Post failed");
    } else {
      // 🔥 Reset
      setContent("");
      setCategory("Discussion");
      setTopic("Design");
      setImages([]);
      setPreviews([]);

      if (onPostCreated) {
        onPostCreated();
      }
    }

    setLoading(false);
  };

  return (
    <div style={{
      marginBottom: "32px",
      background: "var(--surface)",
      border: "1.5px solid var(--border)",
      borderRadius: "12px",
      padding: "20px",
      boxShadow: "var(--shadow)"
    }}>
      {/* TAG SELECTORS */}
      <div style={{
        display: "flex",
        gap: "10px",
        marginBottom: "16px"
      }}>
        <select 
          value={category} 
          onChange={(e) => setCategory(e.target.value)}
          style={{
            flex: 1,
            padding: "8px 12px",
            borderRadius: "8px",
            border: "1.5px solid var(--border)",
            background: "var(--bg)",
            color: "var(--ink)",
            fontFamily: "inherit",
            fontSize: "0.85rem",
            outline: "none"
          }}
        >
          <option value="Discussion">Discussion</option>
          <option value="Question">Question</option>
          <option value="Help Request">Help Request</option>
          <option value="Feedback">Feedback</option>
          <option value="Collaboration">Collaboration</option>
          <option value="Project Update">Project Update</option>
        </select>

        <select 
          value={topic} 
          onChange={(e) => setTopic(e.target.value)}
          style={{
            flex: 1,
            padding: "8px 12px",
            borderRadius: "8px",
            border: "1.5px solid var(--border)",
            background: "var(--bg)",
            color: "var(--ink)",
            fontFamily: "inherit",
            fontSize: "0.85rem",
            outline: "none"
          }}
        >
          <option value="Design">Design</option>
          <option value="Technology">Technology</option>
          <option value="Startups">Startups</option>
          <option value="Marketing">Marketing</option>
          <option value="AI">AI</option>
          <option value="Growth">Growth</option>
        </select>
      </div>

      {/* TEXT */}
      <textarea
        placeholder="Share your thoughts or project updates..."
        value={content}
        onChange={(e) => setContent(e.target.value)}
        style={{
          width: "100%",
          padding: "16px",
          borderRadius: "8px",
          border: "1.5px solid var(--border)",
          background: "var(--bg)",
          fontFamily: "inherit",
          fontSize: "0.95rem",
          color: "var(--ink)",
          resize: "none",
          minHeight: "100px",
          outline: "none",
          transition: "border-color 200ms ease",
          boxSizing: "border-box"
        }}
        onFocus={(e) => e.target.style.borderColor = "var(--accent)"}
        onBlur={(e) => e.target.style.borderColor = "var(--border)"}
      />

      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginTop: "16px" }}>
        {/* MULTIPLE IMAGE INPUT */}
        <label style={{
          display: "inline-flex",
          alignItems: "center",
          gap: "8px",
          color: "var(--ink-muted)",
          cursor: "pointer",
          fontSize: "0.9rem",
          fontWeight: "500",
          padding: "8px 12px",
          borderRadius: "6px",
          border: "1px solid transparent",
          transition: "all 200ms ease"
        }}
        onMouseOver={(e) => {
          e.currentTarget.style.color = "var(--accent)";
          e.currentTarget.style.backgroundColor = "rgba(200,68,26,0.05)";
        }}
        onMouseOut={(e) => {
          e.currentTarget.style.color = "var(--ink-muted)";
          e.currentTarget.style.backgroundColor = "transparent";
        }}
        >
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" style={{width: "16px", height: "16px"}}>
            <rect x="3" y="3" width="18" height="18" rx="2" />
            <circle cx="8.5" cy="8.5" r="1.5" />
            <polyline points="21 15 16 10 5 21" />
          </svg>
          Attach Images
          <input
            type="file"
            accept="image/*"
            multiple
            onChange={handleImageChange}
            style={{ display: "none" }}
          />
        </label>

        {/* BUTTON */}
        <button
          onClick={handlePost}
          disabled={loading}
          style={{
            padding: "10px 24px",
            borderRadius: "8px",
            background: loading ? "var(--ink-muted)" : "var(--accent)",
            color: "#fff",
            border: "none",
            fontWeight: "600",
            cursor: loading ? "not-allowed" : "pointer",
            transition: "background 200ms ease",
            display: "inline-flex",
            alignItems: "center",
            gap: "8px"
          }}
        >
          {loading ? "Posting..." : "Post"}
        </button>
      </div>

      {/* 🔥 IMAGE PREVIEW GRID */}
      {previews.length > 0 && (
        <div
          style={{
            display: "flex",
            gap: "10px",
            marginTop: "16px",
            flexWrap: "wrap",
            paddingTop: "16px",
            borderTop: "1px solid var(--border)"
          }}
        >
          {previews.map((src, i) => (
            <img
              key={i}
              src={src}
              alt="preview"
              style={{
                width: "80px",
                height: "80px",
                objectFit: "cover",
                borderRadius: "8px",
                border: "1px solid var(--border)"
              }}
            />
          ))}
        </div>
      )}
    </div>
  );
}
